class Solution {
public:
    int coinChange(vector<int>& coins, int amount) {
        vector<int> dp(amount+1, amount);
        dp[0] = 0;
        for (int i = 1; i <= amount; i++)
            dp[i] = (i < coins.size()) ? 1 : (i == coins.size()) ? amount : min(coinChange(coins, i-coins[i-1])+1, dp[i-1]);
        return dp[amount];
    }
};

int main() {
    Solution s;
    int t;
    cin >> t;
    while (t--) {
        int n;
        cin >> n;
        vector<int> coins(n);
        int m;
        for (int i = 0; i < n; i++) {
            cin >> m;
            coins[i] = m;
        }
        cout << s.coinChange(coins, n) << endl;
    }
    return 0;
}
